module RefModule(clk, allow, in, out) ;parameter width = 1;  
  input clk, allow ;
  input [width-1:0] in ;
  output [width-1:0] out ;
  reg [width-1:0] out ;
  wire [width-1:0] toBeUpdated;

assign toBeUpdated = allow? in : out; 

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) 
    out = toBeUpdated ; 
endmodule
